import java.util.*;

public class MemoryBreaker {
    // Creating a memory leak to demonstrate JVM Heap exhaustion
    static List<byte[]> leakedMemory = new ArrayList<>();

    public static void main(String[] args) {
        System.out.println("Starting Memory Leak simulation...");
        try {
            while (true) {
                // Allocate 1MB of memory iteratively
                leakedMemory.add(new byte[1024 * 1024]);
            }
        } catch (OutOfMemoryError e) {
            System.err.println("JVM Heap is full! OutOfMemoryError thrown.");
            System.err.println("Objects allocated: " + leakedMemory.size() + " MB");
        }
    }
}

